125→                            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
126→                            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
127→
128→                            for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
129→                            {
130→                                for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
131→                                {
132→                                    q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
133→                                    NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
134→                                    NDS_VEC_VWADD_WV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
135→                                }
136→                            }
137→
138→                            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
139→                            NDS_VEC_VDIV_VX(NDS_VEC_V0, NDS_VEC_V0, count);
140→                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
141→                            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
142→                            NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
143→                            out_tensor += vl;
144→                            cur_ch += vl;
145→                            in_tensor_ch2 -= vl;
146→                        }
147→                    }
148→                    else
149→                    {
150→                        // e32 accumulation: needed for large kernels where count*128 > 32767
151→                        while(in_tensor_ch2 > 0)
152→                        {
153→                            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
154→                            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
155→                            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
156→
157→                            for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
158→                            {
159→                                for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
160→                                {
161→                                    q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
162→                                    NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
163→                                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, cst_one, NDS_VEC_V8);
164→                                }
165→                            }
166→
167→                            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
168→                            NDS_VEC_VDIV_VX(NDS_VEC_V0, NDS_VEC_V0, count);
169→                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
170→                            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
171→                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
172→                            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
173→                            NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
174→                            out_tensor += vl;
175→                            cur_ch += vl;
176→                            in_tensor_ch2 -= vl;
177→                        }
178→                    }
179→                }
180→                else
181→                {
182→                    // for those outputs in boundary as there is no overlapping
183→                    // between ifm and kernel
184→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
185→                    out_tensor += in_tensor_ch;
186→                }
187→            }
188→        }
189→        in_tensor += input_len;
190→    }
191→#elif defined(ENA_DSP_ISA_64)
192→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
193→    const long_t cst_one_q15x4 = 0x0001000100010001;
194→
195→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
196→    {
197→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
198→        {
199→            long ker_y_start = MAX(0, in_y);
200→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
201→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
202→            {
203→                long ker_x_start = MAX(0, in_x);
204→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
205→                uint32_t cur_ch;
206→
207→                if ((ker_y_end > ker_y_start) &&
208→                    (ker_x_end > ker_x_start))
209→                {
210→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
211→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
212→                    {
213→                        suni_t sum_q31x2_0;
214→                        suni_t sum_q31x2_1;
215→                        suni_t sum_q31x2_2;
216→                        suni_t sum_q31x2_3;
217→                        sum_q31x2_0.l0 = 0;
218→                        sum_q31x2_1.l0 = 0;
219→                        sum_q31x2_2.l0 = 0;
220→                        sum_q31x2_3.l0 = 0;
221→
222→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
223→                        {
224→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
225→                            {
226→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
227→                                suni_t in_q7x8 = simd_load_8(pIn, 0);
228→                                long in_q15x4_0 = NDS_DSP_SUNPKD810(in_q7x8.l0);
229→                                long in_q15x4_1 = NDS_DSP_SUNPKD832(in_q7x8.l0);
230→                                sum_q31x2_0.l0 = NDS_DSP_KMABB(sum_q31x2_0.l0, in_q15x4_0, cst_one_q15x4);
231→                                sum_q31x2_1.l0 = NDS_DSP_KMATT(sum_q31x2_1.l0, in_q15x4_0, cst_one_q15x4);
232→                                sum_q31x2_2.l0 = NDS_DSP_KMABB(sum_q31x2_2.l0, in_q15x4_1, cst_one_q15x4);
233→                                sum_q31x2_3.l0 = NDS_DSP_KMATT(sum_q31x2_3.l0, in_q15x4_1, cst_one_q15x4);
234→                            }
235→                        }
236→
237→                        suni_t out_q7x8;
238→                        out_q7x8.b8.b0 = sum_q31x2_0.b32.w0 / count;
239→                        out_q7x8.b8.b1 = sum_q31x2_1.b32.w0 / count;
240→                        out_q7x8.b8.b2 = sum_q31x2_2.b32.w0 / count;
241→                        out_q7x8.b8.b3 = sum_q31x2_3.b32.w0 / count;
242→                        out_q7x8.b8.b4 = sum_q31x2_0.b32.w1 / count;
243→                        out_q7x8.b8.b5 = sum_q31x2_1.b32.w1 / count;
244→                        out_q7x8.b8.b6 = sum_q31x2_2.b32.w1 / count;
245→                        out_q7x8.b8.b7 = sum_q31x2_3.b32.w1 / count;
246→                        simd_save_8((s8_t*)out_tensor, out_q7x8.l0);
247→                        out_tensor += SIMD_NUM_Q7;
248→                    }
249→
250→                    // rest channels
251→                    for (; cur_ch < in_tensor_ch; cur_ch++)
252→                    {
253→                        int sum = 0;
254→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
255→                        {
256→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
257→                            {
258→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
259→                                sum += *pIn;
260→                            }
261→                        }
262→
263→                        *out_tensor++ = sum / count;
264→                    }
265→                }
266→                else
267→                {
268→                    // for those outputs in boundary as there is no overlapping
269→                    // between ifm and kernel
270→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
271→                    out_tensor += in_tensor_ch;
272→                }
273→            }
274→        }
275→        in_tensor += input_len;
276→    }
277→#elif defined(ENA_DSP_ISA)
278→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
279→
280→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
281→    {
282→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
283→        {
284→            long ker_y_start = MAX(0, in_y);
285→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
286→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
287→            {
288→                long ker_x_start = MAX(0, in_x);
289→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
290→                uint32_t cur_ch;
291→
292→                if ((ker_y_end > ker_y_start) &&
293→                    (ker_x_end > ker_x_start))
294→                {
295→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
296→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
297→                    {
298→                        long_t sum_q31_0 = 0;
299→                        long_t sum_q31_1 = 0;
300→                        long_t sum_q31_2 = 0;
301→                        long_t sum_q31_3 = 0;
302→
303→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
304→                        {
305→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
306→                            {
307→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
308→                                suni_t in_q7x4 = simd_load_8(pIn, 0);
309→                                sum_q31_0 += in_q7x4.b8.b0;
310→                                sum_q31_1 += in_q7x4.b8.b1;
311→                                sum_q31_2 += in_q7x4.b8.b2;
312→                                sum_q31_3 += in_q7x4.b8.b3;
313→                            }
314→                        }
315→
316→                        suni_t out_q7x4;
317→                        out_q7x4.b8.b0 = sum_q31_0 / count;
318→                        out_q7x4.b8.b1 = sum_q31_1 / count;
319→                        out_q7x4.b8.b2 = sum_q31_2 / count;
320→                        out_q7x4.b8.b3 = sum_q31_3 / count;
321→                        simd_save_8((s8_t*)out_tensor, out_q7x4.l0);
322→                        out_tensor += SIMD_NUM_Q7;
323→                    }
324→
325→                    // rest channels
326→                    for (; cur_ch < in_tensor_ch; cur_ch++)
327→                    {
328→                        int sum = 0;
329→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
330→                        {
331→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
332→                            {
333→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
334→                                sum += *pIn;
335→                            }
336→                        }
337→
338→                        *out_tensor++ = sum / count;
339→                    }
340→                }
341→                else
342→                {
343→                    // for those outputs in boundary as there is no overlapping
344→                    // between ifm and kernel
345→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
346→                    out_tensor += in_tensor_ch;
347→                }
348→            }
349→        }
350→        in_tensor += input_len;
351→    }
352→#else
353→    int16_t   i_batch, i_ch_in, i_x, i_y;
354→    int16_t   k_x, k_y;
355→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
356→    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;
357→
358→    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
359→    {
360→        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
361→        {
362→            for (i_y = 0; i_y < out_tensor_dim; i_y++)
363→            {
364→                for (i_x = 0; i_x < out_tensor_dim; i_x++)
365→                {
366→                    int       sum = 0;
367→                    int       count = 0;
368→                    for (k_y = i_y * stride - pad; k_y < i_y * stride - pad + ker_dim; k_y++)
369→                    {
370→                        for (k_x = i_x * stride - pad; k_x < i_x * stride - pad + ker_dim; k_x++)
371→                        {
372→                            if (k_y >= 0 && k_x >= 0 && k_y < in_tensor_dim && k_x < in_tensor_dim)
373→                            {
374→                                sum += in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)];
375→                                count++;
376→                            }
377→                        }
378→                    }
379→
380→                    if (count == 0)
381→                    {
382→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = 0;
383→                    }
384→                    else
385→                    {
386→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = sum / count;
387→                    }
388→                }
389→            }
390→        }
391→        in_tensor += input_len;
392→        out_tensor += output_len;
393→    }
394→#endif
395→}
