        NDS_VEC_VADD_VV(NDS_VEC_V18, NDS_VEC_V18, NDS_VEC_V30);
        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V30);
        NDS_VEC_VADD_VV(NDS_VEC_V22, NDS_VEC_V22, NDS_VEC_V30);

